def is_django_module(module: ModuleType) -> bool:
    """Return True if module is part of Django."""
    name = module.__name__
    return name == 'django' or name.startswith('django.')


def is_protected_path(path: Path) -> bool:
    """Return True if path is in a protected directory that shouldn't trigger reload."""
    protected_paths = [
        Path(django.__file__).parent.parent / 'site-packages',
        Path(django.__file__).parent.parent / 'dist-packages',
        Path(django.__file__).parent.parent / 'lib',
    ]
    try:
        resolved = path.resolve()
    except (OSError, RuntimeError):
        return False
    return any(str(resolved).startswith(str(p)) for p in protected_paths)


